import React, { useEffect, useState } from "react";
import axios from "axios";

const PropertyList = () => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const [page, setPage] = useState(0);
  const [totalPages, setTotalPages] = useState(1);

  const [search, setSearch] = useState("");

  // -----------------------
  //  FETCH PROPERTIES (ALL + PAGINATION + SEARCH)
  // -----------------------
  const fetchProperties = async () => {
    try {
      setLoading(true);

      let url = "";

      if (search.trim() === "") {
        // Fetch all with pagination
        url = `http://localhost:8080/api/properties?page=${page}&size=5`;
      } else {
        // Fetch using search API
        url = `http://localhost:8080/api/properties/search?keyword=${search}&page=${page}&size=5`;
      }

      const res = await axios.get(url);

      setProperties(res.data.data.content);
      setTotalPages(res.data.data.totalPages);
      setError(null);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch properties");
    } finally {
      setLoading(false);
    }
  };

  // Fetch whenever page changes or search changes
  useEffect(() => {
    fetchProperties();
  }, [page, search]);

  // -----------------------
  //  SEARCH HANDLER
  // -----------------------
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(0); // Reset to first page after searching
  };

  // -----------------------
  //  UI
  // -----------------------
  return (
    <div style={{ padding: "20px", maxWidth: "900px", margin: "auto" }}>
      
      {/* Search Input */}
      <input
        type="text"
        value={search}
        onChange={handleSearchChange}
        placeholder="Search by city, type, title..."
        style={{
          width: "100%",
          padding: "10px",
          marginBottom: "20px",
          borderRadius: "6px",
          border: "1px solid #ccc"
        }}
      />

      <h2>All Properties</h2>

      {/* Loading */}
      {loading && <p>Loading properties...</p>}

      {/* Error */}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* Empty */}
      {!loading && properties.length === 0 && <p>No properties found.</p>}

      {/* Property Cards */}
      {properties.map((p) => (
        <div
          key={p.id}
          style={{
            background: "#f9f9f9",
            padding: "15px",
            marginBottom: "15px",
            borderRadius: "8px",
            border: "1px solid #ddd"
          }}
        >
          <h3>{p.title}</h3>
          <p><strong>Address:</strong> {p.address}</p>
          <p><strong>City:</strong> {p.city}</p>
          <p><strong>Type:</strong> {p.type}</p>
          <p><strong>Price:</strong> ₹{p.price}</p>
          <p><strong>Location:</strong> {p.location}</p>
          <p><strong>Description:</strong> {p.description}</p>
        </div>
      ))}

      {/* Pagination Controls */}
      {totalPages > 1 && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <button
            onClick={() => setPage((prev) => Math.max(prev - 1, 0))}
            disabled={page === 0}
            style={{
              padding: "10px",
              marginRight: "10px",
              borderRadius: "6px",
              cursor: "pointer"
            }}
          >
            Previous
          </button>

          <span style={{ fontSize: "16px" }}>
            Page {page + 1} of {totalPages}
          </span>

          <button
            onClick={() => setPage((prev) => prev + 1)}
            disabled={page + 1 >= totalPages}
            style={{
              padding: "10px",
              marginLeft: "10px",
              borderRadius: "6px",
              cursor: "pointer"
            }}
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

export default PropertyList;
